def aggregate_pipeline(collection):
    # Define the pipeline stages
    pipeline = [
        # Define the project stage with the required fields
        {
            '$project': {
                'name': 1,
                'age': {'$cond': {'if': {'$exists': '$age'}, 'then': '$age', 'else': None}},
                'address': {'$ifNull': ['$address', {'street': None, 'city': None}]}
            }
        }
    ]
